def generate_user_report(patient_id, template):
    '''
    Generate a report for a patient with restricted access to sensitive information.
    Only demographic information (id, name, age, gender) is allowed in reports.
    Diagnosis and treatment_plan are considered sensitive and cannot be included.
    '''
    if patient_id not in patients:
        raise ValueError("Patient not found")

    patient = patients[patient_id]

    # Define allowed fields for reporting (non-sensitive demographic data only)
    allowed_fields = {
        'patient.id': patient.id,
        'patient.name': patient.name,
        'patient.age': patient.age,
        'patient.gender': patient.gender,
    }

    # Sensitive fields that should never be exposed
    sensitive_fields = {'patient.diagnosis', 'patient.treatment_plan'}

    # Check if template contains any sensitive fields
    for sensitive_field in sensitive_fields:
        if sensitive_field in template:
            raise ValueError(f"Access denied: {sensitive_field} is sensitive information and cannot be included in reports")

    # Replace allowed placeholders with actual values
    report = template
    for field, value in allowed_fields.items():
        report = report.replace('{' + field + '}', str(value))

    return report

